#!/usr/bin/env python3
"""
Centralized Logging Utility for Microservices
Accepts log messages via HTTP requests and writes them to log files.
"""

import os
import json
import threading
from datetime import datetime, timezone
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs
import argparse
import signal
import sys


class LogManager:
    """Manages log file writing with thread safety."""

    def __init__(self, log_dir="logs", default_log_file="app.log", max_file_size_mb=50):
        self.log_dir = log_dir
        self.default_log_file = default_log_file
        self.max_file_size_bytes = max_file_size_mb * 1024 * 1024
        self._lock = threading.Lock()
        self._file_handles = {}

        os.makedirs(self.log_dir, exist_ok=True)

    def _get_log_filepath(self, service_name=None):
        if service_name:
            filename = "%s.log" % service_name
        else:
            filename = self.default_log_file
        return os.path.join(self.log_dir, filename)

    def _rotate_if_needed(self, filepath):
        if os.path.exists(filepath) and os.path.getsize(filepath) >= self.max_file_size_bytes:
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            base, ext = os.path.splitext(filepath)
            rotated_path = "%s_%s%s" % (base, timestamp, ext)
            os.rename(filepath, rotated_path)
            if filepath in self._file_handles:
                self._file_handles[filepath].close()
                del self._file_handles[filepath]

    def _get_file_handle(self, filepath):
        if filepath not in self._file_handles or self._file_handles[filepath].closed:
            self._file_handles[filepath] = open(filepath, "a", encoding="utf-8")
        return self._file_handles[filepath]

    def write_log(self, level, message, service_name=None, metadata=None):
        """Write a log entry to the appropriate log file."""
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S.%f")[:-3]
        level = (level or "INFO").upper()
        service = service_name or "unknown"

        if metadata:
            meta_str = " | metadata=%s" % json.dumps(metadata)
        else:
            meta_str = ""

        log_entry = "[%s] [%s] [%s] %s%s\n" % (timestamp, level, service, message, meta_str)

        with self._lock:
            # Write to service-specific log
            service_filepath = self._get_log_filepath(service_name)
            self._rotate_if_needed(service_filepath)
            fh = self._get_file_handle(service_filepath)
            fh.write(log_entry)
            fh.flush()

            # Also write to the combined log
            if service_name:
                combined_filepath = self._get_log_filepath(None)
                self._rotate_if_needed(combined_filepath)
                fh_combined = self._get_file_handle(combined_filepath)
                fh_combined.write(log_entry)
                fh_combined.flush()

        return log_entry.strip()

    def close_all(self):
        """Close all open file handles."""
        with self._lock:
            for filepath, fh in self._file_handles.items():
                if not fh.closed:
                    fh.close()
            self._file_handles.clear()

    def get_logs(self, service_name=None, level=None, limit=100):
        """Retrieve recent log entries."""
        filepath = self._get_log_filepath(service_name)
        if not os.path.exists(filepath):
            return []

        with self._lock:
            with open(filepath, "r", encoding="utf-8") as f:
                lines = f.readlines()

        if level:
            level_filter = "[%s]" % level.upper()
            lines = [line for line in lines if level_filter in line]

        return [line.strip() for line in lines[-limit:]]

    def get_services(self):
        """List all services that have log files."""
        services = []
        for filename in os.listdir(self.log_dir):
            if filename.endswith(".log") and filename != self.default_log_file:
                services.append(os.path.splitext(filename)[0])
        return sorted(services)


# Global log manager instance
log_manager = None

VALID_LEVELS = {"DEBUG", "INFO", "WARNING", "ERROR", "CRITICAL"}


class LogRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for the logging service."""

    def _send_json_response(self, status_code, data):
        response_body = json.dumps(data, indent=2).encode("utf-8")
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)

    def _read_request_body(self):
        content_length = int(self.headers.get("Content-Length", 0))
        if content_length == 0:
            return None
        body = self.rfile.read(content_length)
        return body.decode("utf-8")

    def do_GET(self):
        """Handle GET requests for retrieving logs and service info."""
        parsed_url = urlparse(self.path)
        path = parsed_url.path.rstrip("/")
        query_params = parse_qs(parsed_url.query)

        if path == "" or path == "/":
            self._handle_health_check()
        elif path == "/logs":
            self._handle_get_logs(query_params)
        elif path == "/services":
            self._handle_get_services()
        elif path.startswith("/logs/"):
            # /logs/<service_name>
            service_name = path.split("/logs/", 1)[1]
            query_params["service"] = [service_name]
            self._handle_get_logs(query_params)
        else:
            self._send_json_response(404, {"error": "Not found", "path": path})

    def do_POST(self):
        """Handle POST requests for submitting log entries."""
        parsed_url = urlparse(self.path)
        path = parsed_url.path.rstrip("/")

        if path == "/log":
            self._handle_post_log()
        elif path == "/logs/bulk":
            self._handle_post_bulk_logs()
        else:
            self._send_json_response(404, {"error": "Not found", "path": path})

    def _handle_health_check(self):
        data = {
            "status": "healthy",
            "service": "centralized-log-server",
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "endpoints": {
                "POST /log": "Submit a single log entry",
                "POST /logs/bulk": "Submit multiple log entries",
                "GET /logs": "Retrieve logs (query params: service, level, limit)",
                "GET /logs/<service>": "Retrieve logs for a specific service",
                "GET /services": "List all services with logs",
            },
        }
        self._send_json_response(200, data)

    def _handle_post_log(self):
        """Process a single log entry submission."""
        try:
            body = self._read_request_body()
            if not body:
                self._send_json_response(400, {"error": "Empty request body"})
                return

            data = json.loads(body)

            message = data.get("message")
            if not message:
                self._send_json_response(400, {"error": "Missing required field: 'message'"})
                return

            level = data.get("level", "INFO").upper()
            if level not in VALID_LEVELS:
                self._send_json_response(400, {
                    "error": "Invalid log level: '%s'. Valid levels: %s" % (level, ", ".join(sorted(VALID_LEVELS)))
                })
                return

            service_name = data.get("service", data.get("service_name"))
            metadata = data.get("metadata")

            # Sanitize inputs
            message = self._sanitize_log_input(message)
            if service_name:
                service_name = self._sanitize_service_name(service_name)

            log_entry = log_manager.write_log(
                level=level,
                message=message,
                service_name=service_name,
                metadata=metadata,
            )

            self._send_json_response(201, {
                "status": "logged",
                "entry": log_entry,
            })

        except json.JSONDecodeError as e:
            self._send_json_response(400, {"error": "Invalid JSON: %s" % str(e)})
        except Exception as e:
            self._send_json_response(500, {"error": "Internal server error: %s" % str(e)})

    def _handle_post_bulk_logs(self):
        """Process multiple log entries at once."""
        try:
            body = self._read_request_body()
            if not body:
                self._send_json_response(400, {"error": "Empty request body"})
                return

            data = json.loads(body)

            if not isinstance(data, dict) or "logs" not in data:
                self._send_json_response(400, {"error": "Expected JSON object with 'logs' array"})
                return

            logs = data["logs"]
            if not isinstance(logs, list):
                self._send_json_response(400, {"error": "'logs' must be an array"})
                return

            # Default service name for the batch
            default_service = data.get("service", data.get("service_name"))

            results = []
            errors = []

            for i, entry in enumerate(logs):
                try:
                    if isinstance(entry, str):
                        # Simple string message
                        message = self._sanitize_log_input(entry)
                        svc = self._sanitize_service_name(default_service) if default_service else None
                        log_entry = log_manager.write_log(
                            level="INFO",
                            message=message,
                            service_name=svc,
                        )
                        results.append(log_entry)
                    elif isinstance(entry, dict):
                        message = entry.get("message")
                        if not message:
                            errors.append({"index": i, "error": "Missing 'message' field"})
                            continue

                        level = entry.get("level", "INFO").upper()
                        if level not in VALID_LEVELS:
                            errors.append({"index": i, "error": "Invalid level: %s" % level})
                            continue

                        service_name = entry.get("service", entry.get("service_name", default_service))
                        metadata = entry.get("metadata")

                        message = self._sanitize_log_input(message)
                        if service_name:
                            service_name = self._sanitize_service_name(service_name)

                        log_entry = log_manager.write_log(
                            level=level,
                            message=message,
                            service_name=service_name,
                            metadata=metadata,
                        )
                        results.append(log_entry)
                    else:
                        errors.append({"index": i, "error": "Invalid entry type"})
                except Exception as e:
                    errors.append({"index": i, "error": str(e)})

            response = {
                "status": "processed",
                "logged": len(results),
                "errors": len(errors),
            }
            if errors:
                response["error_details"] = errors

            self._send_json_response(201 if results else 400, response)

        except json.JSONDecodeError as e:
            self._send_json_response(400, {"error": "Invalid JSON: %s" % str(e)})
        except Exception as e:
            self._send_json_response(500, {"error": "Internal server error: %s" % str(e)})

    def _handle_get_logs(self, query_params):
        """Retrieve log entries with optional filtering."""
        service = query_params.get("service", [None])[0]
        level = query_params.get("level", [None])[0]
        limit_str = query_params.get("limit", ["100"])[0]

        try:
            limit = int(limit_str)
            if limit < 1:
                limit = 1
            elif limit > 10000:
                limit = 10000
        except ValueError:
            self._send_json_response(400, {"error": "Invalid 'limit' parameter"})
            return

        if level and level.upper() not in VALID_LEVELS:
            self._send_json_response(400, {
                "error": "Invalid log level filter: '%s'" % level
            })
            return

        logs = log_manager.get_logs(service_name=service, level=level, limit=limit)

        self._send_json_response(200, {
            "service": service or "all",
            "level_filter": level,
            "count": len(logs),
            "limit": limit,
            "logs": logs,
        })

    def _handle_get_services(self):
        """List all services that have log files."""
        services = log_manager.get_services()
        self._send_json_response(200, {
            "count": len(services),
            "services": services,
        })

    @staticmethod
    def _sanitize_log_input(text):
        """Sanitize log message to prevent log injection."""
        if not isinstance(text, str):
            text = str(text)
        # Remove newlines and carriage returns to prevent log injection
        text = text.replace("\n", " ").replace("\r", " ")
        # Limit message length
        max_length = 10000
        if len(text) > max_length:
            text = text[:max_length] + "... [TRUNCATED]"
        return text

    @staticmethod
    def _sanitize_service_name(name):
        """Sanitize service name for use in filenames."""
        if not name:
            return None
        # Allow only alphanumeric, hyphens, underscores, and dots
        sanitized = ""
        for char in name:
            if char.isalnum() or char in "-_.":
                sanitized += char
            else:
                sanitized += "_"
        # Prevent directory traversal
        sanitized = sanitized.replace("..", "_")
        return sanitized[:64] if sanitized else "unknown"

    def log_message(self, format, *args):
        """Override to log HTTP access to the access log."""
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%d %H:%M:%S")
        client_address = self.client_address[0] if self.client_address else "unknown"
        log_line = "[%s] [ACCESS] %s - %s\n" % (timestamp, client_address, format % args)

        # Write access log
        access_log_path = os.path.join(log_manager.log_dir, "access.log")
        try:
            with open(access_log_path, "a", encoding="utf-8") as f:
                f.write(log_line)
        except Exception:
            pass

        # Also print to stdout
        sys.stderr.write(log_line)


class ThreadedHTTPServer(HTTPServer):
    """HTTP Server that handles each request in a new thread."""
    allow_reuse_address = True

    def process_request(self, request, client_address):
        thread = threading.Thread(target=self._handle_request_thread, args=(request, client_address))
        thread.daemon = True
        thread.start()

    def _handle_request_thread(self, request, client_address):
        try:
            self.finish_request(request, client_address)
        except Exception:
            self.handle_error(request, client_address)
        finally:
            self.shutdown_request(request)


def run_server(host="0.0.0.0", port=8080, log_dir="logs", max_file_size_mb=50):
    """Start the centralized logging HTTP server."""
    global log_manager

    log_manager = LogManager(
        log_dir=log_dir,
        max_file_size_mb=max_file_size_mb,
    )

    server = ThreadedHTTPServer((host, port), LogRequestHandler)

    # Handle graceful shutdown
    def signal_handler(sig, frame):
        print("\nShutting down logging server...")
        log_manager.close_all()
        server.shutdown()
        sys.exit(0)

    signal.signal(signal.SIGINT, signal_handler)
    signal.signal(signal.SIGTERM, signal_handler)

    startup_msg = "Centralized Logging Server started on %s:%d" % (host, port)
    print(startup_msg)
    print("Log directory: %s" % os.path.abspath(log_dir))
    print("Max log file size: %d MB" % max_file_size_mb)
    print("Press Ctrl+C to stop.\n")

    # Log the startup event
    log_manager.write_log(
        level="INFO",
        message=startup_msg,
        service_name="log-server",
    )

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        log_manager.close_all()
        server.server_close()
        print("Server stopped.")


